mapper.update:
/* com.educare.edu.comn.mapper.QuestionChoiceMapper.updateByPk */
	/** updateByPk t_question_choice */
	update t_question_choice
	set upd_de = #{updDe} ,upd_id = #{updId}

		,ch_str = #{chStr}


		,ch_ans_yn = #{chAnsYn}


		,use_yn = #{useYn}

	where qstn_seq = #{qstnSeq} and ch_seq = #{chSeq}

/* com.educare.edu.comn.mapper.QuestionChoiceMapper.updateByFile */
	/** updateByFile t_question_choice */
	update t_question_choice
	set upd_de = #{updDe} ,upd_id = #{updId}

	,ch_fn_org = #{chFnOrg} 
	,ch_fn_rnm = #{chFnRnm}

	where qstn_seq = #{qstnSeq} and ch_seq = #{chSeq}

/* com.educare.edu.comn.mapper.QuestionChoiceMapper.updateUseNByQstnSeq */
	/** updateUseNByQstnSeq t_question_choice */
	update t_question_choice
	set use_yn= 'N'
	where qstn_seq = #{qstnSeq}

mapper.delete:
/* com.educare.edu.comn.mapper.QuestionChoiceMapper.deleteByUseN */
	/** deleteByUseN */
	delete from t_question_choice
	where qstn_seq = #{qstnSeq} and use_yn = 'N'
